=====BEGIN FILE=====
-- bug334: Reintroduce Notes.
--
-- Simple per-user private notes: each authenticated user owns their own notes,
-- sees only their own, and can create / edit / archive them. No cross-user
-- sharing, no complex permissions -- the original Notes design.
--
-- Applied to prod (bqgrpnsvplvicnmzxwkm) 2026-07-03; ledgered as version 20260703160000.
--
-- Surface:
--   public.member_notes         -- owner-private table (one FOR ALL RLS policy)
--   public.member_notes_list    -- security_invoker read view (FE reads here)
--   public.create_member_note   -- SECURITY DEFINER create RPC
--   public.update_member_note   -- SECURITY DEFINER update/archive RPC
--
-- Conventions mirrored: chat_likes_own (owner FOR ALL policy), impersonation
-- RPCs (private impl + public thin wrapper, search_path term empty, REVOKE/GRANT),
-- n_member_feed (security_invoker=true read view).

create table if not exists public.member_notes (
  mn_id         bigint      generated always as identity primary key,
  mn_at         timestamptz not null default now(),
  mn_by         uuid        not null default auth.uid(),
  mn_details    text        not null,
  mn_updated_at timestamptz null,
  is_archived   boolean     not null default false
);

comment on table public.member_notes is
  '"'"'Per-user private notes. Owner-scoped (mn_by). One row per note; is_archived soft-hides. Reintroduced for bug334.'"'"';

create index if not exists member_notes_by_idx
  on public.member_notes (mn_by);

alter table public.member_notes enable row level security;

create policy member_notes_own
  on public.member_notes
  for all to authenticated
  using (mn_by = (select auth.uid()))
  with check (mn_by = (select auth.uid()));

grant select, insert, update on public.member_notes to authenticated;

create or replace view public.member_notes_list
  with (security_invoker = true) as
  select
    mn_id,
    mn_at,
    mn_by,
    mn_details,
    mn_updated_at,
    is_archived
  from public.member_notes
  order by coalesce(mn_updated_at, mn_at) desc;

comment on view public.member_notes_list is
  '"'"'security_invoker read view over public.member_notes. RLS on the base table scopes rows to the caller (mn_by). Newest-touched first.'"'"';

