  p_details text
)
returns bigint
language plpgsql
security definer
set search_path to '"'"''"'"'
as $$
declare
  v_by uuid := (select auth.uid());
  v_id bigint;
begin
  if v_by is null then
    raise exception '"'"'unauthorized'"'"' using errcode = '"'"'42501'"'"';
  end if;

  if p_details is null or length(btrim(p_details)) = 0 then
    raise exception '"'"'invalid_input: note details cannot be empty'"'"'
      using errcode = '"'"'22023'"'"';
  end if;

  insert into public.member_notes (mn_by, mn_details)
  values (v_by, p_details)
  returning mn_id into v_id;

  return v_id;
end;
$$;

